import { useState, useEffect, createContext, useContext, type ReactNode } from 'react';
import { auth } from '../services/api';
import type { LoginResponse } from '../types';

interface AuthContextType {
  user: LoginResponse | null;
  isAuthenticated: boolean;
  isLoading: boolean;
  login: (username: string, password: string) => Promise<void>;
  logout: () => void;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export function AuthProvider({ children }: { children: ReactNode }) {
  const [user, setUser] = useState<LoginResponse | null>(null);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    const token = localStorage.getItem('token');
    const username = localStorage.getItem('username');
    const role = localStorage.getItem('role');
    const expiresIn = localStorage.getItem('expires_in');
    
    if (token && username && role) {
      setUser({
        token,
        username,
        role,
        expires_in: parseInt(expiresIn || '0', 10),
      });
    }
    setIsLoading(false);
  }, []);

  const login = async (username: string, password: string) => {
    const response = await auth.login({ username, password });
    const data = response.data;
    
    localStorage.setItem('token', data.token);
    localStorage.setItem('username', data.username);
    localStorage.setItem('role', data.role);
    localStorage.setItem('expires_in', data.expires_in.toString());
    
    setUser(data);
  };

  const logout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('username');
    localStorage.removeItem('role');
    localStorage.removeItem('expires_in');
    setUser(null);
  };

  return (
    <AuthContext.Provider
      value={{
        user,
        isAuthenticated: !!user,
        isLoading,
        login,
        logout,
      }}
    >
      {children}
    </AuthContext.Provider>
  );
}

export function useAuth() {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
}

import { useState, useEffect } from 'react';
import { Trash2, Edit2, Zap, Tag, FileText, Folder } from 'lucide-react';
import { boosts } from '../services/api';
import type { BoostConfig, BoostConfigCreate, BoostTemplate } from '../types';
import { Button } from '../components/Button';
import { Input } from '../components/Input';
import styles from './Boosts.module.css';

const TIPO_ICONS: Record<string, typeof Zap> = {
  sigla: Tag,
  palavra_chave: FileText,
  categoria: Folder,
};

const TIPO_LABELS: Record<string, string> = {
  sigla: 'Sigla',
  palavra_chave: 'Palavra-chave',
  categoria: 'Categoria',
};

export default function BoostsPage() {
  const [boostsList, setBoostsList] = useState<BoostConfig[]>([]);
  const [templates, setTemplates] = useState<BoostTemplate[]>([]);
  const [loading, setLoading] = useState(true);
  const [filterTipo, setFilterTipo] = useState<string>('');
  const [filterAtivo, setFilterAtivo] = useState<string>('');
  const [showModal, setShowModal] = useState(false);
  const [editingBoost, setEditingBoost] = useState<BoostConfig | null>(null);
  const [showTemplates, setShowTemplates] = useState(false);
  
  const [formData, setFormData] = useState<BoostConfigCreate>({
    nome: '',
    tipo: 'sigla',
    valor: '',
    boost_value: 0.2,
    prioridade: 0,
    ativo: true,
  });

  useEffect(() => {
    loadBoosts();
    loadTemplates();
  }, []);

  const loadBoosts = async () => {
    try {
      const params: { tipo?: string; ativo?: boolean } = {};
      if (filterTipo) params.tipo = filterTipo;
      if (filterAtivo === 'true') params.ativo = true;
      if (filterAtivo === 'false') params.ativo = false;
      
      const response = await boosts.list(params);
      setBoostsList(response.data);
    } catch (err) {
      console.error('Failed to load boosts:', err);
    } finally {
      setLoading(false);
    }
  };

  const loadTemplates = async () => {
    try {
      const response = await boosts.templates();
      setTemplates(response.data);
    } catch (err) {
      console.error('Failed to load templates:', err);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      if (editingBoost) {
        await boosts.update(editingBoost.id, formData);
      } else {
        await boosts.create(formData);
      }
      setShowModal(false);
      setEditingBoost(null);
      resetForm();
      loadBoosts();
    } catch (err) {
      console.error('Failed to save boost:', err);
    }
  };

  const handleEdit = (boost: BoostConfig) => {
    setEditingBoost(boost);
    setFormData({
      nome: boost.nome,
      tipo: boost.tipo,
      valor: boost.valor,
      boost_value: boost.boost_value,
      prioridade: boost.prioridade,
      ativo: boost.ativo,
    });
    setShowModal(true);
  };

  const handleDelete = async (id: string) => {
    if (!confirm('Tem certeza que deseja remover este boost?')) return;
    try {
      await boosts.delete(id);
      loadBoosts();
    } catch (err) {
      console.error('Failed to delete boost:', err);
    }
  };

  const handleToggle = async (boost: BoostConfig) => {
    try {
      await boosts.update(boost.id, { ativo: !boost.ativo });
      loadBoosts();
    } catch (err) {
      console.error('Failed to toggle boost:', err);
    }
  };

  const handleImport = async () => {
    try {
      const response = await boosts.import();
      alert(`Importado: ${response.data.imported}, Já existiam: ${response.data.skipped}`);
      loadBoosts();
    } catch (err) {
      console.error('Failed to import:', err);
    }
  };

  const handleQuickAdd = (template: BoostTemplate) => {
    setFormData({
      nome: template.sigla,
      tipo: 'sigla',
      valor: template.sigla,
      boost_value: 0.2,
      prioridade: boostsList.length + 1,
      ativo: true,
    });
    setShowModal(true);
    setShowTemplates(false);
  };

  const resetForm = () => {
    setFormData({
      nome: '',
      tipo: 'sigla',
      valor: '',
      boost_value: 0.2,
      prioridade: 0,
      ativo: true,
    });
  };

  const openNewModal = () => {
    setEditingBoost(null);
    resetForm();
    setShowModal(true);
  };

  const filteredBoosts = boostsList;

  const siglas = filteredBoosts.filter(b => b.tipo === 'sigla');
  const palavras = filteredBoosts.filter(b => b.tipo === 'palavra_chave');
  const categorias = filteredBoosts.filter(b => b.tipo === 'categoria');

  return (
    <div className={styles.container}>
      <header className={styles.header}>
        <h1>⚡ Boosts</h1>
        <p className={styles.subtitle}>Configure boosts para melhorar relevância das buscas RAG</p>
      </header>

      <div className={styles.toolbar}>
        <div className={styles.filters}>
          <select 
            value={filterTipo} 
            onChange={(e) => { setFilterTipo(e.target.value); loadBoosts(); }}
            className={styles.select}
          >
            <option value="">Todos os tipos</option>
            <option value="sigla">Siglas</option>
            <option value="palavra_chave">Palavras-chave</option>
            <option value="categoria">Categorias</option>
          </select>
          
          <select 
            value={filterAtivo} 
            onChange={(e) => { setFilterAtivo(e.target.value); loadBoosts(); }}
            className={styles.select}
          >
            <option value="">Todos</option>
            <option value="true">Ativos</option>
            <option value="false">Inativos</option>
          </select>
        </div>

        <div className={styles.actions}>
          <Button variant="secondary" onClick={() => setShowTemplates(!showTemplates)}>
            Templates ({templates.length})
          </Button>
          <Button variant="secondary" onClick={handleImport}>
            Importar Siglas
          </Button>
          <Button onClick={openNewModal}>
            + Adicionar Boost
          </Button>
        </div>
      </div>

      {showTemplates && (
        <div className={styles.templatesPanel}>
          <h3>Siglas Disponíveis (clique para adicionar)</h3>
          <div className={styles.templatesList}>
            {templates.map((t) => (
              <button 
                key={t.sigla} 
                className={styles.templateTag}
                onClick={() => handleQuickAdd(t)}
              >
                {t.sigla}
              </button>
            ))}
          </div>
        </div>
      )}

      {loading ? (
        <div className={styles.loading}>Carregando...</div>
      ) : (
        <div className={styles.sections}>
          {siglas.length > 0 && (
            <section className={styles.section}>
              <h2><Tag size={18} /> Siglas ({siglas.length})</h2>
              <div className={styles.list}>
                {siglas.map((boost) => (
                  <BoostCard 
                    key={boost.id} 
                    boost={boost} 
                    onEdit={handleEdit}
                    onDelete={handleDelete}
                    onToggle={handleToggle}
                  />
                ))}
              </div>
            </section>
          )}

          {palavras.length > 0 && (
            <section className={styles.section}>
              <h2><FileText size={18} /> Palavras-chave ({palavras.length})</h2>
              <div className={styles.list}>
                {palavras.map((boost) => (
                  <BoostCard 
                    key={boost.id} 
                    boost={boost} 
                    onEdit={handleEdit}
                    onDelete={handleDelete}
                    onToggle={handleToggle}
                  />
                ))}
              </div>
            </section>
          )}

          {categorias.length > 0 && (
            <section className={styles.section}>
              <h2><Folder size={18} /> Categorias ({categorias.length})</h2>
              <div className={styles.list}>
                {categorias.map((boost) => (
                  <BoostCard 
                    key={boost.id} 
                    boost={boost} 
                    onEdit={handleEdit}
                    onDelete={handleDelete}
                    onToggle={handleToggle}
                  />
                ))}
              </div>
            </section>
          )}

          {filteredBoosts.length === 0 && (
            <div className={styles.empty}>
              Nenhum boost configurado. Clique em "Adicionar Boost" para começar.
            </div>
          )}
        </div>
      )}

      {showModal && (
        <div className={styles.modalOverlay} onClick={() => setShowModal(false)}>
          <div className={styles.modal} onClick={(e) => e.stopPropagation()}>
            <h2>{editingBoost ? 'Editar Boost' : 'Novo Boost'}</h2>
            <form onSubmit={handleSubmit}>
              <div className={styles.formGroup}>
                <label>Tipo</label>
                <select 
                  value={formData.tipo}
                  onChange={(e) => setFormData({ ...formData, tipo: e.target.value as any })}
                  className={styles.select}
                >
                  <option value="sigla">Sigla</option>
                  <option value="palavra_chave">Palavra-chave</option>
                  <option value="categoria">Categoria</option>
                </select>
              </div>

              <Input
                label="Nome"
                value={formData.nome}
                onChange={(e) => setFormData({ ...formData, nome: e.target.value })}
                placeholder={formData.tipo === 'sigla' ? 'REFIS' : 'Vacinação'}
                required
              />

              <Input
                label={formData.tipo === 'sigla' ? 'Sigla (valor)' : 'Valor'}
                value={formData.valor}
                onChange={(e) => setFormData({ ...formData, valor: e.target.value })}
                placeholder={
                  formData.tipo === 'sigla' 
                    ? 'REFIS' 
                    : formData.tipo === 'palavra_chave'
                    ? 'vacina, covid, imunização'
                    : 'saude, educacao'
                }
                required
              />

              <div className={styles.formRow}>
                <div className={styles.formGroup}>
                  <label>Boost (+)</label>
                  <input
                    type="number"
                    step="0.05"
                    min="0"
                    max="1"
                    value={formData.boost_value}
                    onChange={(e) => setFormData({ ...formData, boost_value: parseFloat(e.target.value) })}
                    className={styles.input}
                  />
                </div>

                <div className={styles.formGroup}>
                  <label>Prioridade</label>
                  <input
                    type="number"
                    value={formData.prioridade}
                    onChange={(e) => setFormData({ ...formData, prioridade: parseInt(e.target.value) })}
                    className={styles.input}
                  />
                </div>
              </div>

              <label className={styles.checkbox}>
                <input
                  type="checkbox"
                  checked={formData.ativo}
                  onChange={(e) => setFormData({ ...formData, ativo: e.target.checked })}
                />
                Ativo
              </label>

              <div className={styles.modalActions}>
                <Button type="button" variant="secondary" onClick={() => setShowModal(false)}>
                  Cancelar
                </Button>
                <Button type="submit">
                  Salvar
                </Button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

function BoostCard({ 
  boost, 
  onEdit, 
  onDelete, 
  onToggle 
}: { 
  boost: BoostConfig; 
  onEdit: (b: BoostConfig) => void; 
  onDelete: (id: string) => void;
  onToggle: (b: BoostConfig) => void;
}) {
  const Icon = TIPO_ICONS[boost.tipo] || Tag;

  return (
    <div className={`${styles.card} ${!boost.ativo ? styles.inactive : ''}`}>
      <div className={styles.cardIcon}>
        <Icon size={16} />
      </div>
      <div className={styles.cardContent}>
        <div className={styles.cardHeader}>
          <strong>{boost.nome}</strong>
          <span className={styles.tipoBadge}>{TIPO_LABELS[boost.tipo]}</span>
        </div>
        <div className={styles.cardValue}>{boost.valor}</div>
        <div className={styles.cardMeta}>
          <span className={styles.boostValue}>+{boost.boost_value.toFixed(2)}</span>
          <span>Prioridade: {boost.prioridade}</span>
        </div>
      </div>
      <div className={styles.cardActions}>
        <button 
          className={`${styles.toggleBtn} ${boost.ativo ? styles.active : ''}`}
          onClick={() => onToggle(boost)}
          title={boost.ativo ? 'Desativar' : 'Ativar'}
        >
          <Zap size={14} />
        </button>
        <button className={styles.editBtn} onClick={() => onEdit(boost)}>
          <Edit2 size={14} />
        </button>
        <button className={styles.deleteBtn} onClick={() => onDelete(boost.id)}>
          <Trash2 size={14} />
        </button>
      </div>
    </div>
  );
}

import { useState, useEffect } from 'react';
import { Search, ChevronLeft, ChevronRight } from 'lucide-react';
import { logs } from '../services/api';
import type { Conversa } from '../types';
import styles from './Logs.module.css';

export default function Logs() {
  const [conversas, setConversas] = useState<Conversa[]>([]);
  const [loading, setLoading] = useState(true);
  const [total, setTotal] = useState(0);
  const [page, setPage] = useState(0);
  const [filters, setFilters] = useState({
    busca_texto: '',
    canal: '',
    intent: '',
    decision: '',
  });

  const limit = 20;

  useEffect(() => {
    fetchLogs();
  }, [page, filters]);

  const fetchLogs = async () => {
    setLoading(true);
    try {
      const response = await logs.conversas({
        ...filters,
        busca_texto: filters.busca_texto || undefined,
        canal: filters.canal || undefined,
        intent: filters.intent || undefined,
        decision: filters.decision || undefined,
        limit,
        offset: page * limit,
      });
      setConversas(response.data.conversas);
      setTotal(response.data.count);
    } catch (err) {
      console.error('Failed to fetch logs:', err);
    } finally {
      setLoading(false);
    }
  };

  const totalPages = Math.ceil(total / limit);

  const getStatusColor = (tipo: string) => {
    switch (tipo) {
      case 'SUCCESS': return 'var(--success)';
      case 'FALLBACK': return 'var(--warning)';
      case 'ERROR': return 'var(--error)';
      default: return 'var(--text-muted)';
    }
  };

  return (
    <div className={styles.container}>
      <header className={styles.header}>
        <h1>Logs de Conversas</h1>
        <p className={styles.subtitle}>Histórico de interações</p>
      </header>

      {/* Filters */}
      <div className={styles.filters}>
        <div className={styles.searchBox}>
          <Search size={18} />
          <input
            type="text"
            placeholder="Buscar no texto..."
            value={filters.busca_texto}
            onChange={(e) => setFilters({ ...filters, busca_texto: e.target.value })}
          />
        </div>
        <div className={styles.filterSelects}>
          <select
            value={filters.canal}
            onChange={(e) => setFilters({ ...filters, canal: e.target.value })}
          >
            <option value="">Todos os canais</option>
            <option value="web_widget">Web Widget</option>
            <option value="instagram_dm">Instagram DM</option>
            <option value="facebook_dm">Facebook DM</option>
          </select>
          <select
            value={filters.intent}
            onChange={(e) => setFilters({ ...filters, intent: e.target.value })}
          >
            <option value="">Todos os intents</option>
            <option value="GREETING">Greeting</option>
            <option value="INFO_REQUEST">Info Request</option>
            <option value="CONTACT_REQUEST">Contact Request</option>
            <option value="OUT_OF_SCOPE">Out of Scope</option>
          </select>
          <select
            value={filters.decision}
            onChange={(e) => setFilters({ ...filters, decision: e.target.value })}
          >
            <option value="">Todas as decisões</option>
            <option value="ANSWER_RAG">Answer RAG</option>
            <option value="FALLBACK">Fallback</option>
            <option value="ESCALATE">Escalate</option>
          </select>
        </div>
      </div>

      {/* Results */}
      <div className={styles.tableWrapper}>
        <table className={styles.table}>
          <thead>
            <tr>
              <th>Data</th>
              <th>Canal</th>
              <th>Intent</th>
              <th>Decisão</th>
              <th>Usuário</th>
              <th>Resposta</th>
            </tr>
          </thead>
          <tbody>
            {loading ? (
              <tr>
                <td colSpan={6} className={styles.loading}>Carregando...</td>
              </tr>
            ) : conversas.length === 0 ? (
              <tr>
                <td colSpan={6} className={styles.empty}>Nenhum registro encontrado</td>
              </tr>
            ) : (
              conversas.map((conv) => (
                <tr key={conv.id_conversa}>
                  <td className={styles.date}>
                    {new Date(conv.criado_em).toLocaleString('pt-BR')}
                  </td>
                  <td>
                    <span className={styles.tag}>{conv.canal}</span>
                  </td>
                  <td>{conv.intencao}</td>
                  <td>
                    <span 
                      className={styles.status}
                      style={{ color: getStatusColor(conv.tipo_resposta) }}
                    >
                      {conv.tipo_resposta}
                    </span>
                  </td>
                  <td className={styles.message} title={conv.mensagem_usuario}>
                    {conv.mensagem_usuario.length > 50 
                      ? conv.mensagem_usuario.slice(0, 50) + '...' 
                      : conv.mensagem_usuario}
                  </td>
                  <td className={styles.message} title={conv.mensagem_resposta || ''}>
                    {conv.mensagem_resposta 
                      ? (conv.mensagem_resposta.length > 50 
                          ? conv.mensagem_resposta.slice(0, 50) + '...' 
                          : conv.mensagem_resposta)
                      : '-'}
                  </td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>

      {/* Pagination */}
      <div className={styles.pagination}>
        <span className={styles.pageInfo}>
          Mostrando {page * limit + 1}-{Math.min((page + 1) * limit, total)} de {total}
        </span>
        <div className={styles.pageButtons}>
          <button 
            onClick={() => setPage(p => p - 1)} 
            disabled={page === 0}
          >
            <ChevronLeft size={18} />
          </button>
          <span>{page + 1} / {totalPages || 1}</span>
          <button 
            onClick={() => setPage(p => p + 1)} 
            disabled={page >= totalPages - 1}
          >
            <ChevronRight size={18} />
          </button>
        </div>
      </div>
    </div>
  );
}

import { useState, useEffect, useCallback } from 'react';
import {
  ReactFlow,
  Background,
  Controls,
  MiniMap,
  addEdge,
  useNodesState,
  useEdgesState,
  Handle,
  Position,
} from '@xyflow/react';
import type { Connection, Node, Edge, NodeTypes } from '@xyflow/react';
import '@xyflow/react/dist/style.css';
import { scrap } from '../services/api';
import type { 
  ScrapConfig, 
  ScrapExecuteResponse,
  ScrapResult,
  ScrapSchedule
} from '../types';
import { Button } from '../components/Button';
import { Input } from '../components/Input';
import styles from './Scrap.module.css';

type ScrapNodeData = {
  label: string;
  url?: string;
  listSelector?: string;
  itemSelector?: string;
  fields?: { name: string; selector: string; type: string }[];
  followLinks?: boolean;
  linkSelector?: string;
  maxPages?: number;
  pageParam?: string;
  paginationType?: 'none' | 'next' | 'param';
};

const nodeStyles: React.CSSProperties = {
  padding: '12px 16px',
  borderRadius: '8px',
  background: '#1e1e22',
  border: '1px solid #333',
  color: '#e5e5e5',
  minWidth: '180px',
  fontSize: '13px',
};

function SourceNode({ data, selected }: { data: ScrapNodeData; selected?: boolean }) {
  return (
    <div style={{ 
      ...nodeStyles, 
      border: selected ? '2px solid #a78bfa' : '1px solid #333',
      background: '#1a1a2e'
    }}>
      <Handle type="source" position={Position.Right} style={{ background: '#a78bfa' }} />
      <div style={{ fontWeight: 600, marginBottom: 4 }}>🌐 URL</div>
      <div style={{ fontSize: 11, color: '#888' }}>{data.url || 'Não definido'}</div>
    </div>
  );
}

function ListNode({ data, selected }: { data: ScrapNodeData; selected?: boolean }) {
  return (
    <div style={{ 
      ...nodeStyles, 
      border: selected ? '2px solid #a78bfa' : '1px solid #333',
      background: '#1a2a1a'
    }}>
      <Handle type="target" position={Position.Left} style={{ background: '#22c55e' }} />
      <Handle type="source" position={Position.Right} style={{ background: '#22c55e' }} />
      <div style={{ fontWeight: 600, marginBottom: 4 }}>📋 Lista</div>
      <div style={{ fontSize: 10, color: '#888' }}>
        {data.listSelector || 'Sem seletor'}
      </div>
    </div>
  );
}

function ItemNode({ data, selected }: { data: ScrapNodeData; selected?: boolean }) {
  return (
    <div style={{ 
      ...nodeStyles, 
      border: selected ? '2px solid #a78bfa' : '1px solid #333',
      background: '#2a1a2a'
    }}>
      <Handle type="target" position={Position.Left} style={{ background: '#f472b6' }} />
      <Handle type="source" position={Position.Right} style={{ background: '#f472b6' }} />
      <div style={{ fontWeight: 600, marginBottom: 4 }}>📄 Itens</div>
      <div style={{ fontSize: 10, color: '#888' }}>
        {data.itemSelector || 'Sem seletor'}
      </div>
      {data.fields && data.fields.length > 0 && (
        <div style={{ fontSize: 10, color: '#22c55e', marginTop: 4 }}>
          {data.fields.length} campo(s)
        </div>
      )}
    </div>
  );
}

function DetailNode({ data, selected }: { data: ScrapNodeData; selected?: boolean }) {
  return (
    <div style={{ 
      ...nodeStyles, 
      border: selected ? '2px solid #a78bfa' : '1px solid #333',
      background: '#1a2a2a'
    }}>
      <Handle type="target" position={Position.Left} style={{ background: '#38bdf8' }} />
      <div style={{ fontWeight: 600, marginBottom: 4 }}>🔗 Detalhe</div>
      <div style={{ fontSize: 10, color: '#888' }}>
        {data.url || 'Segue do item'}
      </div>
      {data.fields && data.fields.length > 0 && (
        <div style={{ fontSize: 10, color: '#22c55e', marginTop: 4 }}>
          {data.fields.length} campo(s)
        </div>
      )}
    </div>
  );
}

const nodeTypes: NodeTypes = {
  source: SourceNode,
  list: ListNode,
  item: ItemNode,
  detail: DetailNode,
};

export default function ScrapPage() {
  const [configs, setConfigs] = useState<ScrapConfig[]>([]);
  const [selectedConfig, setSelectedConfig] = useState<ScrapConfig | null>(null);
  const [configName, setConfigName] = useState('');
  const [nodes, setNodes, onNodesChange] = useNodesState([] as any[]);
  const [edges, setEdges, onEdgesChange] = useEdgesState([] as any[]);
  const [activeTab, setActiveTab] = useState<'builder' | 'results' | 'schedules'>('builder');
  const [loading, setLoading] = useState(false);
  const [executeResult, setExecuteResult] = useState<ScrapExecuteResponse | null>(null);
  const [schedules, setSchedules] = useState<ScrapSchedule[]>([]);
  const [results, setResults] = useState<ScrapResult[]>([]);
  const [selectedNode, setSelectedNode] = useState<Node | null>(null);
  const [previewLoading, setPreviewLoading] = useState(false);
  const [showInteractive, setShowInteractive] = useState(false);
  const [interactiveData, setInteractiveData] = useState<any>(null);

  const onConnect = useCallback((params: Connection) => setEdges((eds) => addEdge(params, eds)), [setEdges]);

  const addNode = (type: string) => {
    const id = `${type}_${Date.now()}`;
    const newNode: Node = {
      id,
      type,
      position: { x: 250 + Math.random() * 200, y: 100 + nodes.length * 120 },
      data: { 
        label: type.charAt(0).toUpperCase() + type.slice(1),
        url: type === 'source' ? 'https://...' : undefined,
        listSelector: type === 'list' ? '.lista > li' : undefined,
        itemSelector: type === 'item' ? 'li' : undefined,
        fields: [],
        paginationType: 'none',
      },
    };
    setNodes((nds) => [...nds, newNode]);
  };

  const updateSelectedNode = (key: string, value: any) => {
    if (!selectedNode) return;
    setNodes((nds) =>
      nds.map((node) => {
        if (node.id === selectedNode.id) {
          return { ...node, data: { ...node.data, [key]: value } };
        }
        return node;
      })
    );
  };

  const deleteSelectedNode = () => {
    if (!selectedNode || selectedNode.type === 'source') return;
    setNodes((nds) => nds.filter((n) => n.id !== selectedNode.id));
    setEdges((eds) => eds.filter((e) => e.source !== selectedNode.id && e.target !== selectedNode.id));
    setSelectedNode(null);
  };

  const loadConfigs = async () => {
    try {
      const response = await scrap.configs.list();
      setConfigs(response.data);
    } catch (err) {
      console.error('Failed to load configs:', err);
    }
  };

  const handleSaveConfig = async () => {
    if (!configName) return;
    
    const workflow: any = {
      nodes: nodes.map(n => ({
        id: n.id,
        type: n.type,
        label: n.data.label,
        url: n.data.url,
        listSelector: n.data.listSelector,
        itemSelector: n.data.itemSelector,
        fields: n.data.fields,
        followLinks: n.data.followLinks,
        linkSelector: n.data.linkSelector,
        paginationType: n.data.paginationType,
        maxPages: n.data.maxPages,
      })),
      edges: edges.map(e => ({ source: e.source, target: e.target })),
    };

    try {
      await scrap.configs.create({
        nome: configName,
        url_base: nodes.find(n => n.type === 'source')?.data.url as string || '',
        workflow
      } as any);
      await loadConfigs();
      setConfigName('');
    } catch (err) {
      console.error('Save failed:', err);
    }
  };

  const handleExecute = async () => {
    if (!selectedConfig) return;
    setLoading(true);
    try {
      const response = await scrap.execute(selectedConfig.id, { limit: 20 });
      setExecuteResult(response.data);
      loadResults();
    } catch (err) {
      console.error('Execute failed:', err);
    } finally {
      setLoading(false);
    }
  };

  const loadResults = async () => {
    if (!selectedConfig) return;
    try {
      const response = await scrap.results.list(selectedConfig.id, 10);
      setResults(response.data);
    } catch (err) {
      console.error('Failed to load results:', err);
    }
  };

  const loadSchedules = async () => {
    if (!selectedConfig) return;
    try {
      const response = await scrap.schedules.list(selectedConfig.id);
      setSchedules(response.data);
    } catch (err) {
      console.error('Failed to load schedules:', err);
    }
  };

  useEffect(() => {
    loadConfigs();
  }, []);

  useEffect(() => {
    if (selectedConfig) {
      loadSchedules();
      loadResults();
      setConfigName(selectedConfig.nome);
      
      if ((selectedConfig as any).workflow?.nodes) {
        const wf = (selectedConfig as any).workflow;
        const flowNodes: Node[] = (wf.nodes || []).map((n: any) => ({
          id: n.id,
          type: n.type || 'list',
          position: { x: 100 + Math.random() * 200, y: 100 + Math.random() * 200 },
          data: {
            label: n.label || n.type,
            url: n.url,
            listSelector: n.listSelector,
            itemSelector: n.itemSelector,
            fields: n.fields || [],
            followLinks: n.followLinks,
            linkSelector: n.linkSelector,
            paginationType: n.paginationType,
            maxPages: n.maxPages,
          }
        }));
        const flowEdges: Edge[] = (wf.edges || []).map((e: any) => ({
          id: `${e.source}-${e.target}`,
          source: e.source,
          target: e.target,
        }));
        setNodes(flowNodes);
        setEdges(flowEdges);
      }
    }
  }, [selectedConfig]);

  const handleInteractivePreview = async () => {
    const sourceNode = nodes.find(n => n.type === 'source');
    if (!sourceNode?.data?.url) return;
    setPreviewLoading(true);
    setShowInteractive(true);
    try {
      const response = await scrap.previewInteractive(sourceNode.data.url as string);
      setInteractiveData(response.data);
    } catch (err) {
      console.error('Interactive preview failed:', err);
    } finally {
      setPreviewLoading(false);
    }
  };

  return (
    <div className={styles.container}>
      <header className={styles.header}>
        <h1>🕸️ Scraping</h1>
        <p className={styles.subtitle}>Workflow visual estilo n8n - arraste e conecte os nodes</p>
      </header>

      <div className={styles.layout}>
        <aside className={styles.sidebar}>
          <div className={styles.sidebarSection}>
            <h3>Configurações</h3>
            <Input
              placeholder="Nome da configuração"
              value={configName}
              onChange={(e) => setConfigName(e.target.value)}
            />
            <Button onClick={handleSaveConfig} disabled={!configName || nodes.length === 0}>
              Salvar
            </Button>
          </div>

          <div className={styles.sidebarSection}>
            <h3>Nodes</h3>
            <div style={{ display: 'flex', flexDirection: 'column', gap: 6 }}>
              <Button variant="secondary" onClick={() => addNode('source')} disabled={nodes.some(n => n.type === 'source')}>
                🌐 URL Base
              </Button>
              <Button variant="secondary" onClick={() => addNode('list')}>
                📋 Extrair Lista
              </Button>
              <Button variant="secondary" onClick={() => addNode('item')}>
                📄 Extrair Itens
              </Button>
              <Button variant="secondary" onClick={() => addNode('detail')}>
                🔗 Página Detalhe
              </Button>
            </div>
          </div>

          <div className={styles.sidebarSection}>
            <h3>Salvos</h3>
            <div className={styles.configList}>
              {configs.map((config) => (
                <div
                  key={config.id}
                  className={`${styles.configItem} ${selectedConfig?.id === config.id ? styles.active : ''}`}
                  onClick={() => setSelectedConfig(config)}
                >
                  <span>{config.nome}</span>
                </div>
              ))}
            </div>
          </div>
        </aside>

        <main className={styles.main}>
          <div className={styles.tabs}>
            <button
              className={`${styles.tab} ${activeTab === 'builder' ? styles.active : ''}`}
              onClick={() => setActiveTab('builder')}
            >
              Construtor
            </button>
            <button
              className={`${styles.tab} ${activeTab === 'results' ? styles.active : ''}`}
              onClick={() => setActiveTab('results')}
            >
              Resultados
            </button>
            <button
              className={`${styles.tab} ${activeTab === 'schedules' ? styles.active : ''}`}
              onClick={() => setActiveTab('schedules')}
            >
              Agendamentos
            </button>
          </div>

          {activeTab === 'builder' && (
            <div className={styles.builder}>
              <div className={styles.toolbar}>
                <Button variant="secondary" onClick={handleInteractivePreview} disabled={previewLoading || !nodes.find(n => n.type === 'source')?.data?.url}>
                  {previewLoading ? 'Carregando...' : '🎯 Preview Interativo'}
                </Button>
                <Button onClick={handleExecute} disabled={!selectedConfig || loading}>
                  {loading ? 'Executando...' : '▶ Executar'}
                </Button>
              </div>

              <div className={styles.flowWrapper}>
                <ReactFlow
                  nodes={nodes}
                  edges={edges}
                  onNodesChange={onNodesChange}
                  onEdgesChange={onEdgesChange}
                  onConnect={onConnect}
                  onNodeClick={(_, node) => setSelectedNode(node)}
                  nodeTypes={nodeTypes}
                  fitView
                  style={{ background: '#0a0a0b' }}
                >
                  <Background color="#333" gap={20} />
                  <Controls />
                  <MiniMap nodeColor={() => '#a78bfa'} />
                </ReactFlow>
              </div>

              {selectedNode && (
                <div className={styles.nodeConfig}>
                  <div className={styles.nodeConfigHeader}>
                    <h4>Editar: {String(selectedNode.data?.label || '')}</h4>
                    {selectedNode.type !== 'source' && (
                      <Button variant="secondary" onClick={deleteSelectedNode}>🗑️ Excluir</Button>
                    )}
                  </div>
                  
                  {selectedNode.type === 'source' && (
                    <>
                      <Input
                        label="URL"
                        value={selectedNode.data.url as string || ''}
                        onChange={(e) => updateSelectedNode('url', e.target.value)}
                        placeholder="https://exemplo.com/noticias"
                      />
                    </>
                  )}

                  {selectedNode.type === 'list' && (
                    <>
                      <Input
                        label="Selector da Lista"
                        value={selectedNode.data.listSelector as string || ''}
                        onChange={(e) => updateSelectedNode('listSelector', e.target.value)}
                        placeholder=".noticias > li"
                      />
                      <label className={styles.checkbox}>
                        <input
                          type="checkbox"
                          checked={selectedNode.data.followLinks as boolean || false}
                          onChange={(e) => updateSelectedNode('followLinks', e.target.checked)}
                        />
                        Seguir Links
                      </label>
                      {selectedNode.data.followLinks && (
                        <Input
                          label="Selector do Link"
                          value={selectedNode.data.linkSelector as string || ''}
                          onChange={(e) => updateSelectedNode('linkSelector', e.target.value)}
                          placeholder="a@href"
                        />
                      )}
                      <div className={styles.paginationSection}>
                        <label className={styles.checkbox}>
                          <input
                            type="checkbox"
                            checked={(selectedNode.data.paginationType as string) !== 'none'}
                            onChange={(e) => updateSelectedNode('paginationType', e.target.checked ? 'param' : 'none')}
                          />
                          Paginação
                        </label>
                        {(selectedNode.data.paginationType as string) !== 'none' && (
                          <>
                            <select
                              value={selectedNode.data.paginationType as string || 'param'}
                              onChange={(e) => updateSelectedNode('paginationType', e.target.value)}
                              className={styles.select}
                            >
                              <option value="param">Parâmetro URL (?pag=2)</option>
                              <option value="next">Botão Próxima</option>
                            </select>
                            <Input
                              label="Máx páginas"
                              type="number"
                              value={selectedNode.data.maxPages as number || 5}
                              onChange={(e) => updateSelectedNode('maxPages', parseInt(e.target.value))}
                            />
                          </>
                        )}
                      </div>
                    </>
                  )}

                  {selectedNode.type === 'item' && (
                    <>
                      <Input
                        label="Selector do Item"
                        value={selectedNode.data.itemSelector as string || ''}
                        onChange={(e) => updateSelectedNode('itemSelector', e.target.value)}
                        placeholder="li, article, .item"
                      />
                      <div className={styles.fieldsSection}>
                        <h5>Campos</h5>
                        {((selectedNode.data.fields as any[]) || []).map((field: any, i: number) => (
                          <div key={i} className={styles.fieldRow}>
                            <Input
                              placeholder="Nome"
                              value={field.name}
                              onChange={(e) => {
                                const newFields = [...((selectedNode.data.fields as any[]) || [])];
                                newFields[i] = { ...field, name: e.target.value };
                                updateSelectedNode('fields', newFields);
                              }}
                            />
                            <Input
                              placeholder="Selector"
                              value={field.selector}
                              onChange={(e) => {
                                const newFields = [...((selectedNode.data.fields as any[]) || [])];
                                newFields[i] = { ...field, selector: e.target.value };
                                updateSelectedNode('fields', newFields);
                              }}
                            />
                            <select
                              value={field.type}
                              onChange={(e) => {
                                const newFields = [...((selectedNode.data.fields as any[]) || [])];
                                newFields[i] = { ...field, type: e.target.value };
                                updateSelectedNode('fields', newFields);
                              }}
                              className={styles.select}
                            >
                              <option value="text">Texto</option>
                              <option value="html">HTML</option>
                              <option value="image">Img</option>
                              <option value="attribute">Attr</option>
                            </select>
                            <button 
                              onClick={() => {
                                const newFields = ((selectedNode.data.fields as any[]) || []).filter((_, idx) => idx !== i);
                                updateSelectedNode('fields', newFields);
                              }}
                              className={styles.removeBtn}
                            >✕</button>
                          </div>
                        ))}
                        <Button 
                          variant="secondary" 
                          onClick={() => updateSelectedNode('fields', [...((selectedNode.data.fields as any[]) || []), { name: '', selector: '', type: 'text' }])}
                        >
                          + Campo
                        </Button>
                      </div>
                    </>
                  )}

                  {selectedNode.type === 'detail' && (
                    <>
                      <Input
                        label="URL (opcional - usa link se vazio)"
                        value={selectedNode.data.url as string || ''}
                        onChange={(e) => updateSelectedNode('url', e.target.value)}
                        placeholder="https://..."
                      />
                      <div className={styles.fieldsSection}>
                        <h5>Campos da Página de Detalhe</h5>
                        {((selectedNode.data.fields as any[]) || []).map((field: any, i: number) => (
                          <div key={i} className={styles.fieldRow}>
                            <Input
                              placeholder="Nome"
                              value={field.name}
                              onChange={(e) => {
                                const newFields = [...((selectedNode.data.fields as any[]) || [])];
                                newFields[i] = { ...field, name: e.target.value };
                                updateSelectedNode('fields', newFields);
                              }}
                            />
                            <Input
                              placeholder="Selector"
                              value={field.selector}
                              onChange={(e) => {
                                const newFields = [...((selectedNode.data.fields as any[]) || [])];
                                newFields[i] = { ...field, selector: e.target.value };
                                updateSelectedNode('fields', newFields);
                              }}
                            />
                            <select
                              value={field.type}
                              onChange={(e) => {
                                const newFields = [...((selectedNode.data.fields as any[]) || [])];
                                newFields[i] = { ...field, type: e.target.value };
                                updateSelectedNode('fields', newFields);
                              }}
                              className={styles.select}
                            >
                              <option value="text">Texto</option>
                              <option value="html">HTML</option>
                              <option value="image">Img</option>
                              <option value="attribute">Attr</option>
                            </select>
                            <button 
                              onClick={() => {
                                const newFields = ((selectedNode.data.fields as any[]) || []).filter((_, idx) => idx !== i);
                                updateSelectedNode('fields', newFields);
                              }}
                              className={styles.removeBtn}
                            >✕</button>
                          </div>
                        ))}
                        <Button 
                          variant="secondary" 
                          onClick={() => updateSelectedNode('fields', [...((selectedNode.data.fields as any[]) || []), { name: '', selector: '', type: 'text' }])}
                        >
                          + Campo
                        </Button>
                      </div>
                    </>
                  )}
                </div>
              )}

              {showInteractive && (
                <div className={styles.interactiveModal}>
                  <div className={styles.interactiveHeader}>
                    <h3>🎯 Selecione os Elementos</h3>
                    <button className={styles.closeBtn} onClick={() => setShowInteractive(false)}>✕</button>
                  </div>
                  <div className={styles.interactiveContent}>
                    <div className={styles.interactivePreview}>
                      {interactiveData?.interactive_html ? (
                        <div 
                          className={styles.clickablePreview}
                          dangerouslySetInnerHTML={{ __html: interactiveData.interactive_html }}
                          onClick={(e) => {
                            const target = e.target as HTMLElement;
                            let el: HTMLElement | null = target;
                            while (el && !el.getAttribute('data-scrap-selector')) {
                              el = el.parentElement;
                            }
                            if (!el || !selectedNode) return;
                            
                            const selector = el.getAttribute('data-scrap-selector');
                            if (selectedNode.type === 'list') {
                              updateSelectedNode('listSelector', selector);
                            } else if (selectedNode.type === 'item') {
                              updateSelectedNode('itemSelector', selector);
                            } else if (selectedNode.type === 'detail') {
                              updateSelectedNode('linkSelector', selector);
                            }
                          }}
                        />
                      ) : (
                        <div className={styles.loadingPreview}>Carregando...</div>
                      )}
                    </div>
                  </div>
                </div>
              )}
            </div>
          )}

          {activeTab === 'results' && (
            <div className={styles.results}>
              {executeResult && (
                <div className={styles.resultSummary}>
                  <span className={styles.success}>✓ {executeResult.items_count} itens extraídos</span>
                </div>
              )}
              <div className={styles.resultsList}>
                {results.map((result) => (
                  <div key={result.id} className={styles.resultCard}>
                    <div className={styles.resultHeader}>
                      <span className={`${styles.status} ${styles[result.status]}`}>{result.status}</span>
                      <span>{new Date(result.executed_at).toLocaleString()}</span>
                      <span>{result.items_count} itens</span>
                    </div>
                    <div className={styles.resultData}>
                      {result.data.slice(0, 3).map((item: any, i: number) => (
                        <div key={i} className={styles.resultItem}>
                          {Object.entries(item).slice(0, 4).map(([k, v]) => (
                            <div key={k}><strong>{k}:</strong> {String(v)?.substring(0, 100)}</div>
                          ))}
                        </div>
                      ))}
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}

          {activeTab === 'schedules' && (
            <div className={styles.schedules}>
              {selectedConfig && (
                <div className={styles.scheduleActions}>
                  <Button variant="secondary" onClick={async () => {
                    await scrap.schedules.create({ config_id: selectedConfig.id, schedule_type: 'manual', enabled: true });
                    loadSchedules();
                  }}>
                    + Manual
                  </Button>
                  <Button variant="secondary" onClick={async () => {
                    await scrap.schedules.create({ config_id: selectedConfig.id, schedule_type: 'periodic', interval_minutes: 60, enabled: true });
                    loadSchedules();
                  }}>
                    + A cada hora
                  </Button>
                </div>
              )}
              <div className={styles.schedulesList}>
                {schedules.map((schedule) => (
                  <div key={schedule.id} className={styles.scheduleCard}>
                    <div className={styles.scheduleInfo}>
                      <span className={styles.scheduleType}>
                        {schedule.schedule_type === 'periodic' ? 'Periódico' : 'Manual'}
                      </span>
                      {schedule.interval_minutes && <span> a cada {schedule.interval_minutes} min</span>}
                    </div>
                    <label className={styles.checkbox}>
                      <input 
                        type="checkbox" 
                        checked={schedule.enabled}
                        onChange={async () => {
                          await scrap.schedules.update(schedule.id, !schedule.enabled);
                          loadSchedules();
                        }}
                      />
                      Ativo
                    </label>
                  </div>
                ))}
              </div>
            </div>
          )}
        </main>
      </div>
    </div>
  );
}
